class DetailFolderComponent {
    constructor(offreService, offreS, userServ, toastr, router, activatedRoute) {
        this.offreService = offreService;
        this.offreS = offreS;
        this.userServ = userServ;
        this.toastr = toastr;
        this.router = router;
        this.activatedRoute = activatedRoute;
        this.title = "Details du dossier";
        this.loading = false;
        this.sectionSubject = Object(rxjs__WEBPACK_IMPORTED_MODULE_1__["of"])([]);
    }
    ngOnInit() {
        const a = this.activatedRoute.snapshot.paramMap.get('idFolder');
        this.offreService.getOneFolder(a).subscribe((data) => {
            this.loading = true;
            this.dataInfo = data.data;
            console.log(this.dataInfo);
        });
    }
    remarque(a) {
        const rmq = {
            remarque: a,
            id: this.dataInfo.id
        };
        this.offreService.setRemarque(rmq).subscribe((res) => {
            if (res.error === false) {
                this.toastr.success('remarque ajouté', '', {
                    timeOut: 2000
                });
                window.location.reload();
            }
            else {
                this.toastr.error('Une erreur est survenue', '', {
                    timeOut: 2000
                });
            }
        });
    }
    republishedOffer(offerId, folderId, infoPublier) {
        console.log("Offre ID : " + offerId + " - infoPublier : " + infoPublier);
        this.offreS.reUpdateOffreQuizzArchive(offerId, folderId, { publier: infoPublier }).subscribe((response) => {
            this.toastr.success(`Offre reactivée`, '', {
                timeOut: 5000
            });
            this.router.navigateByUrl("/projet");
        }, (error) => {
            this.toastr.error("Problème lors de la réactivation de l'offre !", '', {
                timeOut: 5000
            });
        });
    }
    publier(idOffre, lastValue) {
        const now = new Date().toISOString();
        this.offreService.updatePublier({ publier: lastValue, publicationDate: (lastValue ? now : null) }, idOffre).subscribe((res) => {
            // this.folder[this.findIndexdossierById(id)].publier = lastValue;
            if (lastValue) {
                this.toastr.success(`Offre Publié`, '', {
                    timeOut: 4000
                });
            }
            else {
                this.toastr.success(`Offre non Publié`, '', {
                    timeOut: 4000
                });
            }
        });
    }
    archiver(idOffre, lastValue) {
        this.offreService.updateArchive({ archived: lastValue }, idOffre).subscribe((res) => {
            if (lastValue) {
                this.offreService.updatePublier({ publier: false }, idOffre).subscribe((res) => {
                    this.dataInfo.offre.publier = false;
                });
                this.toastr.success('Offre Archivé', '', {
                    timeOut: 4000
                });
            }
            else {
                this.toastr.success('Offre non Archivé', '', {
                    timeOut: 4000
                });
            }
        });
    }
}
