    // tslint:disable-next-line: typedef
    checkTel(controls) {
        const regExp = new RegExp(/^[+]*[(]{0,1}[0-9]{1,4}[)]{0,1}[-\s\./0-9]*$/);
        if (regExp.test(controls.value)) {
            return null;
        }
        else {
            return { checkTel: true };
        }
    }
    // tslint:disable-next-line: typedef
    checkCode(controls) {
        const regExp = new RegExp(/^[-\s\./0-9]{1,5}$/);
        if (regExp.test(controls.value)) {
            return null;
        }
        else {
            return { checkCode: true };
        }
    }
