    goTo(path, b) {
        if (path.includes('candidat/registration')) {
            console.log(b.id);
            if (localStorage.getItem('idUser') === null) {
                this.offreService.setOffre(b.id);
                this.router.navigateByUrl('candidat/registration');
                this.closeOffre();
            }
            else {
                this.offreService.setOffre(b.id);
                const userId = parseInt(localStorage.getItem('idUser'), 10);
                // === NOUVEAU : contrôle CV côté front ===
                this.userServ.getProfilData(userId).subscribe((data) => {
                    const profile = data.profile || {};
                    if (!profile.cvPath) {
                        this.toastr.error("Vous devez d'abord télécharger votre CV dans votre profil candidat avant de postuler.", '', { timeOut: 4000 });
                        this.router.navigateByUrl('/candidat/profile');
                        return;
                    }
                    // CV OK -> on postule
                    this.postulationService.postule({ userId: userId, offreId: b.id }).subscribe(response => {
                        console.log(response);
                        this.toastr.success(response.message, '', {
                            timeOut: 2000
                        });
                        this.router.navigateByUrl(path);
                        this.closeOffre();
                    }, error => {
                        this.toastr.error(error.error.message === "Validation error" ?
                            "Vous avez déjà postulé à cette offre" :
                            error.error.message, '', { timeOut: 4000 });
                    });
                });
                // =======================================
            }
        }
        else {
            this.offreService.setOffre(b.id);
            this.router.navigateByUrl(path);
            this.closeOffre();
        }
    }
    goToURL(a, template) {
        if (a.name.includes('Se connecter')) {
            this.openModal(template, 'recruteur');
            this.sousMenu = 'active';
        }
        else if (a.name.includes('deconnecter')) {
            this.isLoading = true;
            localStorage.clear();
            const data = [{
                    name: 'Se connecter',
                    mat: 'account_circle'
                }];
            this.userServ.setMenu(data);
            this.isRecruteur = false;
            this.isCandidat = false;
            this.isTalenta = false;
            window.location.assign('/');
            //window.location.reload();
        }
        else {
            this.router.navigateByUrl(a.path);
            this.isDropdowned = false;
            this.isDropdowned1 = false;
            this.isMenuCollapsed = true;
        }
    }
