    onSelectedFile(event) {
        const fileList = event.target.files;
        if (fileList.length > 0) {
            const file = fileList[0];
            this.cvU = event.target.files[0];
            const reader = new FileReader();
            reader.onprogress = (evt) => {
                if (evt.lengthComputable) {
                    this.progressFile = Math.round((evt.loaded / evt.total) * 100);
                }
            };
            reader.onload = (e) => {
                this.progressFile = 100;
                this.cv = e.target.result;
                setTimeout(() => { this.progressFile = 0; }, 2000);
            };
            reader.readAsDataURL(event.target.files[0]);
            this.formData.set('cv', file, file.name);
        }
    }
    generatePdf(action, resume) {
        const documentDefinition = this.getDocumentDefinition(resume);
        switch (action) {
            case 'open':
                pdfmake_build_pdfmake__WEBPACK_IMPORTED_MODULE_6___default.a.createPdf(documentDefinition).open();
                break;
            case 'print':
                pdfmake_build_pdfmake__WEBPACK_IMPORTED_MODULE_6___default.a.createPdf(documentDefinition).print();
                break;
            case 'download':
                pdfmake_build_pdfmake__WEBPACK_IMPORTED_MODULE_6___default.a.createPdf(documentDefinition).download();
                break;
            case 'send':
                pdfmake_build_pdfmake__WEBPACK_IMPORTED_MODULE_6___default.a.createPdf(documentDefinition).getBlob((blob) => {
                    const file = new File([blob], `Infos-${resume.firstName}-${resume.lastName}.pdf`, { type: 'application/pdf' });
                    this.formData.set('infos', file, `Infos-${resume.firstName}-${resume.lastName}.pdf`);
                });
                break;
            default:
                pdfmake_build_pdfmake__WEBPACK_IMPORTED_MODULE_6___default.a.createPdf(documentDefinition).open();
                break;
        }
    }
