    parseTime(totalSeconds) {
        let mins = Math.floor(totalSeconds / 60);
        let secs = Math.round(totalSeconds % 60);
        mins = (mins < 10 ? '0' : '') + mins;
        secs = (secs < 10 ? '0' : '') + secs;
        return `${mins}:${secs}`;
    }
